module asyn_fifo #(
    parameter	WIDTH = 8,
    parameter 	DEPTH = 16,
    parameter ADDR_WIDTH = $clog2(DEPTH)
) (
    input 					wclk,
    input 					rclk,
    input 					wrstn,
    input					rrstn,
    input 					winc,
    input 			 		rinc,
    input 		[WIDTH-1:0]	wdata,
    output reg wfull,
    output reg rempty,
    output reg [WIDTH-1:0]	rdata
);


    reg [ADDR_WIDTH:0] wptr, rptr;
    wire [ADDR_WIDTH:0] wptr_gray, rptr_gray;
    wire [ADDR_WIDTH:0] wptr_next, rptr_next;
    wire wfull_next, rempty_next;

    dual_port_RAM #(
        .DEPTH(DEPTH),
        .WIDTH(WIDTH)
    ) ram_inst (
        .wclk(wclk),
        .wenc(winc),
        .waddr(waddr),
        .wdata(wdata),
        .rclk(rclk),
        .renc(rinc),
        .raddr(raddr),
        .rdata(rdata)
    );

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wptr <= 0;
        end else if (winc && !wfull) begin
            wptr <= wptr + 1'b1;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rptr <= 0;
        end else if (rinc && !rempty) begin
            rptr <= rptr + 1'b1;
        end
    end

    reg [ADDR_WIDTH:0] rptr_sync1, rptr_sync2;
    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            rptr_sync1 <= 0;
            rptr_sync2 <= 0;
        end else begin
            rptr_sync1 <= rptr;
            rptr_sync2 <= rptr_sync1;
        end
    end

    reg [ADDR_WIDTH:0] wptr_sync1, wptr_sync2;
    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            wptr_sync1 <= 0;
            wptr_sync2 <= 0;
        end else begin
            wptr_sync1 <= wptr;
            wptr_sync2 <= wptr_sync1;
        end
    end

    assign wptr_gray = (wptr ^ (wptr >> 1));
    assign rptr_gray = (rptr ^ (rptr >> 1));

    assign wptr_next = wptr + 1'b1;
    assign rptr_next = rptr + 1'b1;

    assign wfull_next = (wptr_next == rptr_sync2);
    assign rempty_next = (wptr == rptr_sync2);

    always @(posedge wclk or negedge wrstn) begin
        if (!wrstn) begin
            wfull <= 1'b0;
        end else begin
            wfull <= wfull_next;
        end
    end

    always @(posedge rclk or negedge rrstn) begin
        if (!rrstn) begin
            rempty <= 1'b1;
        end else begin
            rempty <= rempty_next;
        end
    end

endmodule

module dual_port_RAM #(parameter DEPTH = 16,  parameter WIDTH = 8)
(
	 input wclk	,
	 input wenc	,
	 input [$clog2(DEPTH)-1:0] waddr  ,
	 input [WIDTH-1:0] wdata ,
	 input rclk	,
	 input renc	,
	 input [$clog2(DEPTH)-1:0] raddr ,
	 output reg [WIDTH-1:0] rdata 		
);

reg [WIDTH-1:0] RAM_MEM [0:DEPTH-1];

always @(posedge wclk) begin
	if(wenc)
		RAM_MEM[waddr] <= wdata;
end 

always @(posedge rclk) begin
	if(renc)
		rdata <= RAM_MEM[raddr];
end 

endmodule
